def check_value(x):
    if x > 10:
        return 'Greater than 10'
    elif x == 10:
        return 'Equal to 10'
    else:
        return 'Less than 10'

def categorize_number(num):
    if num > 0:
        return 'Positive'
    elif num < 0:
        return 'Negative'
    else:
        return 'Zero'

def get_grade(score):
    if score >= 90:
        return 'A'
    elif score >= 80:
        return 'B'
    elif score >= 70:
        return 'C'
    elif score >= 60:
        return 'D'
    else:
        return 'F'
